import unreal

include_hidden = {{include_hidden}}
large_bounds_threshold = {{large_bounds_threshold}}
check_mobility = {{check_mobility}}
check_collision = {{check_collision}}
collision_scope = {{collision_scope}}
report_style = {{report_style}}
qa_mode = {{qa_mode}}
max_items_per_group = {{max_items_per_group}}
select_found_issues = {{select_found_issues}}
ignore_editorbinder_qa_helpers = {{ignore_editorbinder_qa_helpers}}

max_items_per_group = max(1, int(max_items_per_group))
collision_scope = str(collision_scope).strip().lower()
report_style = str(report_style).strip().lower()
if report_style not in ("compact", "detailed", "qa", "machine"):
    report_style = "compact"
if report_style == "qa":
    qa_mode = True

actor_subsystem = unreal.get_editor_subsystem(unreal.EditorActorSubsystem)
all_actors = [actor for actor in actor_subsystem.get_all_level_actors() if actor is not None]

PREFIX = "EB Audit"

def log_line(message=""):
    unreal.log(f"{PREFIX} | {message}")

def warn_line(message):
    unreal.log_warning(f"{PREFIX} | {message}")

def actor_label(actor):
    try:
        return actor.get_actor_label()
    except Exception:
        return actor.get_name()

def actor_folder_path(actor):
    try:
        return str(actor.get_folder_path()).replace("\\", "/")
    except Exception:
        return ""

def is_editorbinder_qa_actor(actor):
    return actor_folder_path(actor).startswith("EditorBinder_QA/") or actor_label(actor).startswith("QA_")

def is_editorbinder_qa_helper(actor):
    label = actor_label(actor)
    folder_path = actor_folder_path(actor)
    helper_prefixes = (
        "QA_ENV_",
        "QA_Light_",
        "QA_LABEL_",
        "QA_PAD_",
        "QA_BORDER_",
        "QA_START_",
        "QA_GUIDE_",
        "QA_SNAP_Target_",
        "QA_T4_Expected_Cell_",
    )
    if label.startswith(helper_prefixes):
        return True
    if folder_path.startswith("EditorBinder_QA/00_"):
        return True
    return False

def is_actor_hidden(actor):
    for method_name in ("is_hidden_ed", "get_is_temporarily_hidden_in_editor"):
        try:
            return bool(getattr(actor, method_name)())
        except Exception:
            pass
    try:
        return bool(actor.get_editor_property("hidden"))
    except Exception:
        return False

def actor_components(actor, component_class):
    components = []
    try:
        components.extend(list(actor.get_components_by_class(component_class)))
    except Exception:
        pass

    for property_name in ("static_mesh_component", "root_component"):
        try:
            component = actor.get_editor_property(property_name)
            if component and component not in components and isinstance(component, component_class):
                components.append(component)
        except Exception:
            pass

    try:
        component = actor.static_mesh_component
        if component and component not in components and isinstance(component, component_class):
            components.append(component)
    except Exception:
        pass

    return components

def component_property(component, property_name):
    try:
        return component.get_editor_property(property_name)
    except Exception:
        return None

def component_mobility_name(component):
    value = component_property(component, "mobility")
    static_value = getattr(unreal.ComponentMobility, "STATIC", None)
    stationary_value = getattr(unreal.ComponentMobility, "STATIONARY", None)
    movable_value = getattr(unreal.ComponentMobility, "MOVABLE", None)

    if static_value is not None and value == static_value:
        return "STATIC"
    if stationary_value is not None and value == stationary_value:
        return "STATIONARY"
    if movable_value is not None and value == movable_value:
        return "MOVABLE"

    text = str(value).upper() if value is not None else ""
    if "STATIONARY" in text:
        return "STATIONARY"
    if "MOVABLE" in text:
        return "MOVABLE"
    if "STATIC" in text:
        return "STATIC"
    return text

def max_bounds_size(actor):
    try:
        _origin, extent = actor.get_actor_bounds(False)
        return max(abs(extent.x), abs(extent.y), abs(extent.z)) * 2.0
    except Exception:
        return 0.0

def has_bad_scale(actor):
    try:
        scale = actor.get_actor_scale3d()
        return scale.x <= 0 or scale.y <= 0 or scale.z <= 0
    except Exception:
        return False

def has_missing_static_mesh(actor):
    for component in actor_components(actor, unreal.StaticMeshComponent):
        if component_property(component, "static_mesh") is None:
            return True
    return False

def has_non_static_static_mesh(actor):
    for component in actor_components(actor, unreal.StaticMeshComponent):
        mobility = component_mobility_name(component)
        if mobility in ("MOVABLE", "STATIONARY"):
            return True
    return False

def collision_components_for_actor(actor):
    if collision_scope == "all_primitives":
        return actor_components(actor, unreal.PrimitiveComponent)
    return actor_components(actor, unreal.StaticMeshComponent)

def has_no_collision_component(actor):
    for component in collision_components_for_actor(actor):
        try:
            collision_enabled = component.get_collision_enabled()
        except Exception:
            collision_enabled = component_property(component, "collision_enabled")
        if "NO_COLLISION" in str(collision_enabled).upper():
            return True
    return False

def unique_actors(actors):
    result = []
    for actor in actors:
        if actor is not None and actor not in result:
            result.append(actor)
    return result

def category_count(category):
    return len(category["items"])

def category_expected_count(category):
    return len(category["expected_items"])

def category_real_count(category):
    return len(category["real_items"])

def split_actor_items(items):
    expected = []
    real = []
    for actor in items:
        if qa_mode and is_editorbinder_qa_actor(actor):
            expected.append(actor)
        else:
            real.append(actor)
    return expected, real

def split_duplicate_labels(labels, label_map):
    expected = []
    real = []
    for label in labels:
        actors = label_map.get(label, [])
        if qa_mode and actors and all(is_editorbinder_qa_actor(actor) for actor in actors):
            expected.append(label)
        else:
            real.append(label)
    return expected, real

def duplicate_label_actors(labels, label_map):
    actors = []
    for label in labels:
        actors.extend(label_map.get(label, []))
    return unique_actors(actors)

def issue_total(categories, field_name):
    return sum(len(category[field_name]) for category in categories)

def issue_groups(categories, field_name):
    return sum(1 for category in categories if category[field_name])

def severity_rank(severity):
    return {"ERROR": 3, "WARN": 2, "INFO": 1}.get(severity, 0)

def highest_severity(categories, field_name):
    rank = 0
    label = "OK"
    for category in categories:
        if not category[field_name]:
            continue
        current_rank = severity_rank(category["severity"])
        if current_rank > rank:
            rank = current_rank
            label = category["severity"]
    return label

def result_line(categories):
    real_total = issue_total(categories, "real_items")
    real_groups = issue_groups(categories, "real_items")
    expected_total = issue_total(categories, "expected_items")
    expected_groups = issue_groups(categories, "expected_items")

    if real_total > 0:
        return (
            "NEEDS REVIEW",
            f"RESULT: NEEDS REVIEW - {real_total} real issue(s) in {real_groups} group(s); "
            f"highest severity={highest_severity(categories, 'real_items')}"
        )
    if qa_mode and expected_total > 0:
        return (
            "QA PASS",
            f"RESULT: QA PASS - {expected_total} expected QA test case(s) in {expected_groups} group(s); no real scene issues"
        )
    return ("CLEAN", "RESULT: CLEAN - no issues found")

def category_row(category, field_name):
    count = len(category[field_name])
    status = "OK" if count == 0 else category["severity"]
    return f"{category['short_name']:<27} {count:>5}  {status:<5}  {category['action']}"

def format_item(category, item):
    if category["kind"] == "duplicate_label":
        return f"{item} ({len(labels.get(item, []))} actors)"
    if category["short_name"] == "Large bounds":
        return f"{actor_label(item)} size={max_bounds_size(item):.1f}"
    return actor_label(item)

def report_items(category, field_name, title_prefix):
    items = category[field_name]
    if not items:
        return
    log_line(f"{title_prefix}: {category['short_name']} ({len(items)})")
    for item in items[:max_items_per_group]:
        log_line(f"  - {format_item(category, item)}")
    remaining = len(items) - max_items_per_group
    if remaining > 0:
        log_line(f"  ... {remaining} more hidden by Max Items Per Group")

def report_next_actions(categories):
    actionable = [category for category in categories if category["real_items"] and category["action"] != "Review manually"]
    if not actionable:
        return
    log_line("")
    log_line("Next actions")
    for category in actionable:
        log_line(f"  - {category['short_name']}: {category['action']}")

def log_machine_block(categories, status):
    real_total = issue_total(categories, "real_items")
    expected_total = issue_total(categories, "expected_items")
    log_line("")
    log_line("EB_AUDIT_SUMMARY_START")
    log_line(f"status={status.replace(' ', '_')}")
    log_line(f"real_issues_total={real_total}")
    log_line(f"expected_qa_cases_total={expected_total}")
    log_line(f"actors_scanned={len(actors_to_scan)}")
    log_line(f"actors_total={len(all_actors)}")
    log_line(f"ignored_qa_helpers={len(ignored_helpers)}")
    for category in categories:
        key = category["key"]
        log_line(f"real_{key}={len(category['real_items'])}")
        log_line(f"expected_{key}={len(category['expected_items'])}")
    log_line("EB_AUDIT_SUMMARY_END")

ignored_helpers = [actor for actor in all_actors if ignore_editorbinder_qa_helpers and is_editorbinder_qa_helper(actor)]
scan_pool = [actor for actor in all_actors if actor not in ignored_helpers]
actors_to_scan = scan_pool if include_hidden else [actor for actor in scan_pool if not is_actor_hidden(actor)]

labels = {}
for actor in actors_to_scan:
    labels.setdefault(actor_label(actor), []).append(actor)

duplicate_labels = [label for label, actors in labels.items() if len(actors) > 1]
hidden_actors = [actor for actor in scan_pool if is_actor_hidden(actor)]
bad_scale_actors = [actor for actor in actors_to_scan if has_bad_scale(actor)]
huge_bounds_actors = [actor for actor in actors_to_scan if max_bounds_size(actor) > large_bounds_threshold]
missing_mesh_actors = [actor for actor in actors_to_scan if has_missing_static_mesh(actor)]
non_static_mesh_actors = [actor for actor in actors_to_scan if check_mobility and has_non_static_static_mesh(actor)]
no_collision_actors = [actor for actor in actors_to_scan if check_collision and has_no_collision_component(actor)]
static_mesh_component_count = sum(len(actor_components(actor, unreal.StaticMeshComponent)) for actor in actors_to_scan)
collision_component_count = sum(len(collision_components_for_actor(actor)) for actor in actors_to_scan)

expected_duplicate_labels, real_duplicate_labels = split_duplicate_labels(duplicate_labels, labels)
expected_hidden, real_hidden = split_actor_items(hidden_actors)
expected_bad_scale, real_bad_scale = split_actor_items(bad_scale_actors)
expected_huge_bounds, real_huge_bounds = split_actor_items(huge_bounds_actors)
expected_missing_mesh, real_missing_mesh = split_actor_items(missing_mesh_actors)
expected_non_static_mesh, real_non_static_mesh = split_actor_items(non_static_mesh_actors)
expected_no_collision, real_no_collision = split_actor_items(no_collision_actors)

categories = [
    {
        "key": "duplicate_labels",
        "short_name": "Duplicate labels",
        "severity": "WARN",
        "action": "Rename duplicates",
        "kind": "duplicate_label",
        "items": duplicate_labels,
        "expected_items": expected_duplicate_labels,
        "real_items": real_duplicate_labels,
    },
    {
        "key": "hidden_actors",
        "short_name": "Hidden actors",
        "severity": "INFO",
        "action": "Review manually",
        "kind": "actor",
        "items": hidden_actors,
        "expected_items": expected_hidden,
        "real_items": real_hidden,
    },
    {
        "key": "bad_scale",
        "short_name": "Bad scale",
        "severity": "ERROR",
        "action": "Run Reset Bad Scale",
        "kind": "actor",
        "items": bad_scale_actors,
        "expected_items": expected_bad_scale,
        "real_items": real_bad_scale,
    },
    {
        "key": "large_bounds",
        "short_name": "Large bounds",
        "severity": "WARN",
        "action": "Review transform/scale",
        "kind": "actor",
        "items": huge_bounds_actors,
        "expected_items": expected_huge_bounds,
        "real_items": real_huge_bounds,
    },
    {
        "key": "missing_static_mesh",
        "short_name": "Missing static mesh",
        "severity": "ERROR",
        "action": "Fix asset reference",
        "kind": "actor",
        "items": missing_mesh_actors,
        "expected_items": expected_missing_mesh,
        "real_items": real_missing_mesh,
    },
    {
        "key": "non_static_mobility",
        "short_name": "Non-static mesh mobility",
        "severity": "INFO",
        "action": "Run Set Selected Actors Mobility",
        "kind": "actor",
        "items": non_static_mesh_actors,
        "expected_items": expected_non_static_mesh,
        "real_items": real_non_static_mesh,
    },
    {
        "key": "no_collision",
        "short_name": "No collision",
        "severity": "WARN",
        "action": "Run Set Collision Profile",
        "kind": "actor",
        "items": no_collision_actors,
        "expected_items": expected_no_collision,
        "real_items": real_no_collision,
    },
]

status, result_message = result_line(categories)

log_line("")
log_line("================================================================")
if status == "NEEDS REVIEW":
    warn_line(result_message)
else:
    log_line(result_message)
log_line("Scene Cleanup Audit Report")
log_line("================================================================")
log_line(f"Actors scanned: {len(actors_to_scan)} / {len(all_actors)}")
if ignored_helpers:
    log_line(f"Ignored EditorBinder QA helper actors: {len(ignored_helpers)}")
log_line(f"StaticMeshComponents scanned: {static_mesh_component_count}")
log_line(f"Collision scope: {collision_scope}; components scanned: {collision_component_count}")
log_line(f"Report style: {report_style}; QA mode: {qa_mode}")
log_line("")

if qa_mode:
    expected_total = issue_total(categories, "expected_items")
    real_total = issue_total(categories, "real_items")
    log_line("QA mode")
    log_line(f"  Expected QA cases detected: {expected_total}")
    log_line(f"  Real scene issues detected: {real_total}")
    log_line("")

log_line("Summary")
log_line("  Category                     Count  Level  Action")
log_line("  ---------------------------  -----  -----  -------------------------------")
for category in categories:
    log_line("  " + category_row(category, "real_items"))

if qa_mode and issue_total(categories, "expected_items") > 0:
    log_line("")
    log_line("Expected QA test cases")
    log_line("  Category                     Count  Level  Action")
    log_line("  ---------------------------  -----  -----  -------------------------------")
    for category in categories:
        log_line("  " + category_row(category, "expected_items"))

if report_style in ("detailed", "qa"):
    log_line("")
    log_line("Details - real issues")
    for category in categories:
        report_items(category, "real_items", "Real")

    if qa_mode:
        log_line("")
        log_line("Details - expected QA cases")
        for category in categories:
            report_items(category, "expected_items", "QA")

report_next_actions(categories)

if report_style == "machine":
    log_machine_block(categories, status)

if select_found_issues:
    issue_actors = []
    for category in categories:
        if category["kind"] == "duplicate_label":
            issue_actors.extend(duplicate_label_actors(category["real_items"], labels))
        else:
            issue_actors.extend(category["real_items"])
    issue_actors = unique_actors(issue_actors)
    actor_subsystem.set_selected_level_actors(issue_actors)
    log_line(f"Selected real issue actors: {len(issue_actors)}")

log_line("")
log_line("End of report")
log_line("================================================================")

# Param: columns | int | 5 | Columns | min=1 | step=1
# Param: spacing_x | float | 200 | Spacing X | step=10
# Param: spacing_y | float | 200 | Spacing Y | step=10
# Param: preserve_z | bool | True | Preserve Existing Z
# Param: sort_by_label | bool | True | Sort By Label
import unreal

columns = {{columns}}
spacing_x = {{spacing_x}}
spacing_y = {{spacing_y}}
preserve_z = {{preserve_z}}
sort_by_label = {{sort_by_label}}

actor_subsystem = unreal.get_editor_subsystem(unreal.EditorActorSubsystem)
selected_actors = [actor for actor in actor_subsystem.get_selected_level_actors() if actor is not None]

def actor_label(actor):
    try:
        return actor.get_actor_label()
    except Exception:
        return actor.get_name()

if len(selected_actors) < 2:
    unreal.log_warning("Select at least two actors to distribute in a grid.")
else:
    actors = sorted(selected_actors, key=actor_label) if sort_by_label else list(selected_actors)
    origin = actors[0].get_actor_location()
    with unreal.ScopedEditorTransaction("Distribute Selected Actors In Grid"):
        for index, actor in enumerate(actors):
            row = index // columns
            column = index % columns
            current = actor.get_actor_location()
            target_z = current.z if preserve_z else origin.z
            target = unreal.Vector(origin.x + column * spacing_x, origin.y + row * spacing_y, target_z)
            actor.modify()
            actor.set_actor_location(target, False, False)
    unreal.log(f"Distributed {len(actors)} actor(s) in a grid with {columns} column(s).")

# Param: root_folder | path | Environment/ByMesh | Root Folder
# Param: include_actor_class_fallback | bool | True | Include Actor Class Fallback
import re
import unreal

root_folder = {{root_folder}}
include_actor_class_fallback = {{include_actor_class_fallback}}

actor_subsystem = unreal.get_editor_subsystem(unreal.EditorActorSubsystem)
selected_actors = [actor for actor in actor_subsystem.get_selected_level_actors() if actor is not None]

def actor_components(actor, component_class):
    components = []
    try:
        components.extend(list(actor.get_components_by_class(component_class)))
    except Exception:
        pass

    for property_name in ("static_mesh_component", "root_component"):
        try:
            component = actor.get_editor_property(property_name)
            if component and component not in components and isinstance(component, component_class):
                components.append(component)
        except Exception:
            pass

    try:
        component = actor.static_mesh_component
        if component and component not in components and isinstance(component, component_class):
            components.append(component)
    except Exception:
        pass

    return components

def safe_folder_segment(value):
    cleaned = re.sub(r"[^A-Za-z0-9_\-]+", "_", str(value).strip())
    return cleaned.strip("_") or "Unknown"

def mesh_name_for_actor(actor):
    for component in actor_components(actor, unreal.StaticMeshComponent):
        try:
            static_mesh = component.get_editor_property("static_mesh")
        except Exception:
            static_mesh = None
        if static_mesh is not None:
            try:
                return static_mesh.get_name()
            except Exception:
                return str(static_mesh).split("'")[1] if "'" in str(static_mesh) else str(static_mesh)
    if include_actor_class_fallback:
        return actor.get_class().get_name()
    return ""

if not selected_actors:
    unreal.log_warning("No actors are selected.")
elif not root_folder.strip():
    unreal.log_warning("Root Folder is empty.")
else:
    changed_count = 0
    skipped_count = 0
    failed_count = 0
    root = root_folder.strip().strip("/")
    with unreal.ScopedEditorTransaction("Organize Selected Actors By Static Mesh"):
        for actor in selected_actors:
            mesh_name = mesh_name_for_actor(actor)
            if not mesh_name:
                skipped_count += 1
                continue
            try:
                actor.modify()
                actor.set_folder_path(f"{root}/{safe_folder_segment(mesh_name)}")
                changed_count += 1
            except Exception as exc:
                failed_count += 1
                unreal.log_warning(f"Could not organize actor {actor.get_name()}: {exc}")
    unreal.log(
        f"Organized {changed_count} actor(s) by Static Mesh. "
        f"Skipped {skipped_count}. Failed {failed_count}."
    )

# Param: check_missing_mesh | bool | True | Check Missing Mesh
# Param: check_scale | bool | True | Check Bad Scale
# Param: check_bounds | bool | True | Check Huge Bounds
# Param: bounds_threshold | float | 10000 | Bounds Threshold | min=1 | step=100
import unreal

check_missing_mesh = {{check_missing_mesh}}
check_scale = {{check_scale}}
check_bounds = {{check_bounds}}
bounds_threshold = {{bounds_threshold}}

actor_subsystem = unreal.get_editor_subsystem(unreal.EditorActorSubsystem)
all_actors = [actor for actor in actor_subsystem.get_all_level_actors() if actor is not None]

def actor_label(actor):
    try:
        return actor.get_actor_label()
    except Exception:
        return actor.get_name()

def is_actor_hidden(actor):
    for method_name in ("is_hidden_ed", "get_is_temporarily_hidden_in_editor"):
        try:
            return bool(getattr(actor, method_name)())
        except Exception:
            pass
    try:
        return bool(actor.get_editor_property("hidden"))
    except Exception:
        return False

def actor_components(actor, component_class):
    components = []
    try:
        components.extend(list(actor.get_components_by_class(component_class)))
    except Exception:
        pass

    for property_name in ("static_mesh_component", "root_component"):
        try:
            component = actor.get_editor_property(property_name)
            if component and component not in components and isinstance(component, component_class):
                components.append(component)
        except Exception:
            pass

    try:
        component = actor.static_mesh_component
        if component and component not in components and isinstance(component, component_class):
            components.append(component)
    except Exception:
        pass

    return components

def has_missing_static_mesh(actor):
    components = actor_components(actor, unreal.StaticMeshComponent)
    for component in components:
        try:
            if component.get_editor_property("static_mesh") is None:
                return True
        except Exception:
            continue
    return False

def has_bad_scale(actor):
    try:
        scale = actor.get_actor_scale3d()
        return scale.x <= 0 or scale.y <= 0 or scale.z <= 0
    except Exception:
        return False

def has_huge_bounds(actor):
    try:
        _origin, extent = actor.get_actor_bounds(False)
        return max(abs(extent.x), abs(extent.y), abs(extent.z)) * 2.0 > bounds_threshold
    except Exception:
        return False

matches = []
static_mesh_component_count = 0
for actor in all_actors:
    static_mesh_component_count += len(actor_components(actor, unreal.StaticMeshComponent))
    reasons = []
    if is_actor_hidden(actor):
        reasons.append("hidden")
    if check_missing_mesh and has_missing_static_mesh(actor):
        reasons.append("missing mesh")
    if check_scale and has_bad_scale(actor):
        reasons.append("bad scale")
    if check_bounds and has_huge_bounds(actor):
        reasons.append("huge bounds")
    if reasons:
        matches.append(actor)
        unreal.log_warning(f"Suspicious actor: {actor_label(actor)} ({', '.join(reasons)})")

actor_subsystem.set_selected_level_actors(matches)
if not matches:
    unreal.log_warning(
