def hit_value(hit_result, property_name):
    tuple_value = hit_tuple_value(hit_result, property_name)
    if tuple_value is not None:
        return tuple_value
    try:
        return getattr(hit_result, property_name)
    except Exception:
        return hit_result.get_editor_property(property_name)

def hit_tuple(hit_result):
    try:
        return hit_result.to_tuple()
    except Exception:
        return None

def hit_tuple_value(hit_result, property_name):
    values = hit_tuple(hit_result)
    if values is None:
        return None

    tuple_indices = {
        "blocking_hit": 0,
        "b_blocking_hit": 0,
        "initial_overlap": 1,
        "time": 2,
        "distance": 3,
        "location": 4,
        "impact_point": 5,
        "normal": 6,
        "impact_normal": 7,
        "phys_mat": 8,
        "actor": 9,
        "hit_actor": 9,
        "component": 10,
        "hit_component": 10,
        "trace_start": 16,
        "trace_end": 17,
    }
    index = tuple_indices.get(property_name)
    if index is None or index >= len(values):
        return None
    return values[index]

def hit_location(hit_result):
    for property_name in ("impact_point", "location"):
        try:
            location = hit_value(hit_result, property_name)
            if location is not None:
                return location
        except Exception:
            continue
    return None

def hit_blocks(hit_result):
    values = hit_tuple(hit_result)
    if values is not None and len(values) > 0:
        return bool(values[0])

    for property_name in ("blocking_hit", "b_blocking_hit"):
        try:
            return bool(hit_value(hit_result, property_name))
        except Exception:
            continue
    return hit_location(hit_result) is not None

def extract_hit_result(raw_hit):
    if raw_hit is None:
        return None

    if isinstance(raw_hit, (list, tuple)):
        did_hit = None
        hit_candidate = None

        for item in raw_hit:
            if isinstance(item, bool):
                did_hit = item
                continue
            if hit_location(item) is not None:
                hit_candidate = item

        if did_hit is False:
            return None
        if hit_candidate is not None and (did_hit is True or hit_blocks(hit_candidate)):
            return hit_candidate
        return None

    if hit_blocks(raw_hit) and hit_location(raw_hit) is not None:
        return raw_hit
    return None

def object_type_queries():
    try:
        values = unreal.Array(unreal.ObjectTypeQuery)
    except Exception:
        values = []
    seen = set()
    for index in range(1, 33):
        for name in (f"OBJECT_TYPE_QUERY{index}", f"OBJECT_TYPE_QUERY_{index}"):
            try:
                value = getattr(unreal.ObjectTypeQuery, name)
                key = str(value)
                if key not in seen:
                    values.append(value)
                    seen.add(key)
            except Exception:
                continue
    for channel_name in (
        "ECC_WORLD_STATIC",
        "ECC_WORLD_DYNAMIC",
        "ECC_PHYSICS_BODY",
        "ECC_DESTRUCTIBLE",
        "WORLD_STATIC",
        "WORLD_DYNAMIC",
        "PHYSICS_BODY",
        "DESTRUCTIBLE",
    ):
        try:
            channel = getattr(unreal.CollisionChannel, channel_name)
            value = unreal.SystemLibrary.convert_to_object_type(channel)
            key = str(value)
            if key not in seen:
                values.append(value)
                seen.add(key)
        except Exception:
            continue
    return values

