def best_hit_from_multi(raw_hits):
    if not raw_hits:
        return None
    try:
        hits = list(raw_hits)
    except Exception:
        hit_result = extract_hit_result(raw_hits)
        return hit_result

    for raw_hit in hits:
        hit_result = extract_hit_result(raw_hit)
        if hit_result is not None and hit_location(hit_result) is not None:
            return hit_result
    return None

def single_trace_segment(context, context_label, start, end, actors_to_ignore, draw_type):
    errors = []
    ignore_array = actor_array(actors_to_ignore)
    try:
        for trace_type in trace_type_queries() or [unreal.TraceTypeQuery.TRACE_TYPE_QUERY1]:
            raw_hit = unreal.SystemLibrary.line_trace_single(
                context,
                start,
                end,
                trace_type,
                trace_complex,
                ignore_array,
                draw_type,
                False,
            )
            hit_result = extract_hit_result(raw_hit)
            if hit_result is not None and hit_location(hit_result) is not None:
                return hit_result, f"{context_label} line trace hit: {trace_type}"
    except Exception as exc:
        errors.append(f"visibility trace error: {exc}")

    try:
        for trace_type in trace_type_queries() or [unreal.TraceTypeQuery.TRACE_TYPE_QUERY1]:
            raw_hits = unreal.SystemLibrary.line_trace_multi(
                context,
                start,
                end,
                trace_type,
                trace_complex,
                ignore_array,
                draw_type,
                False,
            )
            hit_result = best_hit_from_multi(raw_hits)
            if hit_result is not None and hit_location(hit_result) is not None:
                return hit_result, f"{context_label} multi trace hit: {trace_type}"
    except Exception as exc:
        errors.append(f"visibility multi error: {exc}")

    for profile_name in ("BlockAll", "BlockAllDynamic", "PhysicsActor"):
        try:
            raw_hit = unreal.SystemLibrary.line_trace_single_by_profile(
                context,
                start,
                end,
                profile_name,
                trace_complex,
                ignore_array,
                draw_type,
                False,
            )
            hit_result = extract_hit_result(raw_hit)
            if hit_result is not None and hit_location(hit_result) is not None:
                return hit_result, f"{context_label} profile trace hit: {profile_name}"
        except Exception as exc:
            errors.append(f"profile {profile_name} error: {exc}")

    for profile_name in ("BlockAll", "BlockAllDynamic", "PhysicsActor"):
        try:
            raw_hits = unreal.SystemLibrary.line_trace_multi_by_profile(
                context,
                start,
                end,
                profile_name,
                trace_complex,
                ignore_array,
                draw_type,
                False,
            )
            hit_result = best_hit_from_multi(raw_hits)
            if hit_result is not None and hit_location(hit_result) is not None:
                return hit_result, f"{context_label} profile multi trace hit: {profile_name}"
        except Exception as exc:
            errors.append(f"profile multi {profile_name} error: {exc}")

    object_types = object_type_queries()
    if object_types:
        try:
            raw_hit = unreal.SystemLibrary.line_trace_single_for_objects(
                context,
                start,
                end,
                object_types,
                trace_complex,
                ignore_array,
                draw_type,
                False,
            )
            hit_result = extract_hit_result(raw_hit)
            if hit_result is not None and hit_location(hit_result) is not None:
                return hit_result, f"{context_label} object line trace hit"
        except Exception as exc:
            errors.append(f"object trace error: {exc}")

        try:
            raw_hits = unreal.SystemLibrary.line_trace_multi_for_objects(
                context,
                start,
                end,
                object_types,
                trace_complex,
                ignore_array,
                draw_type,
                False,
            )
            hit_result = best_hit_from_multi(raw_hits)
            if hit_result is not None and hit_location(hit_result) is not None:
                return hit_result, f"{context_label} object multi trace hit"
        except Exception as exc:
            errors.append(f"object multi error: {exc}")
    else:
        errors.append("object type list was empty")

    if errors:
        return None, "line trace miss; " + " | ".join(errors[:4])
    return None, "line trace miss"

def trace_down_for_actor(actor, start, end, actors_to_ignore, draw_type):
    max_segment_length = 100000.0
    total_distance = max(start.z - end.z, 1.0)
    segment_count = max(1, int((total_distance + max_segment_length - 1.0) // max_segment_length))
    last_status = "line trace miss"

    for segment_index in range(segment_count):
        alpha_a = segment_index / segment_count
        alpha_b = (segment_index + 1) / segment_count
        segment_start = unreal.Vector(
            start.x + (end.x - start.x) * alpha_a,
            start.y + (end.y - start.y) * alpha_a,
            start.z + (end.z - start.z) * alpha_a,
        )
        segment_end = unreal.Vector(
            start.x + (end.x - start.x) * alpha_b,
            start.y + (end.y - start.y) * alpha_b,
            start.z + (end.z - start.z) * alpha_b,
        )
        for context_label, context in trace_contexts(actor):
            hit_result, status = single_trace_segment(
                context,
                context_label,
                segment_start,
                segment_end,
                actors_to_ignore,
                draw_type,
            )
            last_status = status
            if hit_result is not None:
                return hit_result, f"{status}; segment {segment_index + 1}/{segment_count}"

    return None, last_status

def nearly_same_location(a, b, tolerance=0.1):
    return (
        abs(a.x - b.x) <= tolerance
        and abs(a.y - b.y) <= tolerance
        and abs(a.z - b.z) <= tolerance
    )

def move_actor_to_location(actor, target_location):
    actor.modify()

    move_errors = []
    try:
        actor.set_actor_location(target_location, False, True)
    except TypeError:
        try:
            actor.set_actor_location(target_location, False, False)
        except Exception as exc:
            move_errors.append(f"set_actor_location: {exc}")
    except Exception as exc:
        move_errors.append(f"set_actor_location: {exc}")

    new_location = actor.get_actor_location()
    if nearly_same_location(new_location, target_location):
        return True, new_location, "set_actor_location"

    try:
        unreal.EditorLevelLibrary.set_actor_location(actor, target_location, False, True)
        new_location = actor.get_actor_location()
        if nearly_same_location(new_location, target_location):
            return True, new_location, "EditorLevelLibrary.set_actor_location"
    except Exception as exc:
        move_errors.append(f"EditorLevelLibrary.set_actor_location: {exc}")

    return False, new_location, "; ".join(move_errors) or "location did not change"

def try_native_snap_to_floor(actor):
    if not native_snap_fallback:
        return False, actor.get_actor_location(), "native fallback disabled"

    before = actor.get_actor_location()
    actor_subsystem.set_selected_level_actors([actor])
    commands = (
        "SNAPTOFLOOR",
        "ACTOR SNAPTOFLOOR",
        "ACTOR ALIGN SNAPTOFLOOR",
    )
    errors = []
    for command in commands:
        try:
            unreal.SystemLibrary.execute_console_command(editor_world, command)
        except Exception as exc:
            errors.append(f"{command}: {exc}")
            continue
        after = actor.get_actor_location()
        if not nearly_same_location(before, after):
            return True, after, f"native editor command {command}"

    return False, actor.get_actor_location(), "; ".join(errors) or "native snap command did not move actor"

if not selected_actors:
    unreal.log_warning("No actors are selected.")
elif editor_world is None:
    unreal.log_error("Could not get the editor world.")
else:
    snapped_count = 0
    missed_count = 0
    failed_move_count = 0
    draw_type = unreal.DrawDebugTrace.FOR_DURATION if draw_debug else unreal.DrawDebugTrace.NONE

    with unreal.ScopedEditorTransaction("Snap Selected Actors To Ground"):
        for actor_index, actor in enumerate(selected_actors):
            actor_location = actor.get_actor_location()
            start_z_offset = min(max(trace_distance * 0.01, 10.0), 100.0)
            start = unreal.Vector(actor_location.x, actor_location.y, actor_location.z + start_z_offset)
            end = unreal.Vector(actor_location.x, actor_location.y, actor_location.z - trace_distance)

            actors_to_ignore = list(selected_actors) if ignore_other_selected_actors else [actor]
            if actor not in actors_to_ignore:
                actors_to_ignore.append(actor)

            hit_result, trace_status = trace_down_for_actor(actor, start, end, actors_to_ignore, draw_type)
            if hit_result is None:
                native_ok, native_location, native_status = try_native_snap_to_floor(actor)
                if native_ok:
                    snapped_count += 1
                    if log_details and actor_index < log_detail_limit:
                        unreal.log(
                            f"Snap detail: {actor_label(actor)} old={actor_location} "
                            f"new={native_location} status={native_status}; python trace status={trace_status}"
                        )
                    continue

                missed_count += 1
                if log_details and actor_index < log_detail_limit:
                    unreal.log_warning(
                        f"Snap miss: {actor_label(actor)} start={start} end={end} "
                        f"status={trace_status}; native={native_status}"
                    )
                continue

            ground_location = hit_location(hit_result)
            if ground_location is None:
                missed_count += 1
                if log_details and actor_index < log_detail_limit:
                    unreal.log_warning(f"Snap miss: {actor_label(actor)} hit result had no location.")
                continue

            target_location = unreal.Vector(
                ground_location.x,
                ground_location.y,
                ground_location.z + z_offset,
            )
            moved_ok, new_location, move_status = move_actor_to_location(actor, target_location)

            if log_details and actor_index < log_detail_limit:
                unreal.log(
                    f"Snap detail: {actor_label(actor)} old={actor_location} hit={ground_location} "
                    f"target={target_location} new={new_location} moved_ok={moved_ok} status={move_status}"
                )

            if moved_ok:
                snapped_count += 1
            else:
                failed_move_count += 1
                if log_details and actor_index < log_detail_limit:
                    unreal.log_warning(f"Snap move failed: {actor_label(actor)} status={move_status}")

    actor_subsystem.set_selected_level_actors(selected_actors)

    unreal.log(
        f"Snapped {snapped_count} actor(s) to trace hit location. "
        f"Failed moves: {failed_move_count}. Missed {missed_count} actor(s)."
    )

