# Param: mobility | enum | MOVABLE | Mobility | options=STATIC,STATIONARY,MOVABLE
import unreal

mobility = {{mobility}}
actor_subsystem = unreal.get_editor_subsystem(unreal.EditorActorSubsystem)
selected_actors = [actor for actor in actor_subsystem.get_selected_level_actors() if actor is not None]

def actor_label(actor):
    try:
        return actor.get_actor_label()
    except Exception:
        return actor.get_name()

def mobility_enum_value(name):
    normalized = str(name).strip().upper()
    value = getattr(unreal.ComponentMobility, normalized, None)
    if value is not None:
        return value, normalized
    aliases = {
        "STATIC": getattr(unreal.ComponentMobility, "STATIC", None),
        "STATIONARY": getattr(unreal.ComponentMobility, "STATIONARY", None),
        "MOVABLE": getattr(unreal.ComponentMobility, "MOVABLE", None),
    }
    return aliases.get(normalized), normalized

def actor_components_with_mobility(actor):
    components = []

    try:
        root = actor.get_root_component()
        if root and root not in components:
            components.append(root)
    except Exception:
        pass

    for property_name in ("root_component", "static_mesh_component"):
        try:
            component = actor.get_editor_property(property_name)
            if component and component not in components:
                components.append(component)
        except Exception:
            pass

    try:
        component = actor.static_mesh_component
        if component and component not in components:
            components.append(component)
    except Exception:
        pass

    try:
        for component in actor.get_components_by_class(unreal.SceneComponent):
            if component and component not in components:
                components.append(component)
    except Exception:
        pass

    result = []
    for component in components:
        try:
            component.get_editor_property("mobility")
            result.append(component)
        except Exception:
            pass
    return result

def set_component_mobility(component, value):
    try:
        component.modify()
        component.set_editor_property("mobility", value)
        return True, "set_editor_property"
    except Exception as exc:
        first_error = str(exc)

    try:
        component.modify()
        component.set_mobility(value)
        return True, "set_mobility"
    except Exception as exc:
        return False, first_error + "; " + str(exc)

if not selected_actors:
    unreal.log_warning("No actors are selected.")
else:
    mobility_value, mobility_name = mobility_enum_value(mobility)
    if mobility_value is None:
        unreal.log_warning(f"Unknown mobility value: {mobility}. Use STATIC, STATIONARY, or MOVABLE.")
    else:
        changed_components = 0
        scanned_components = 0
        failed_components = 0
        actors_without_mobility_components = 0

        with unreal.ScopedEditorTransaction("Set Selected Actors Mobility"):
            for actor in selected_actors:
                components = actor_components_with_mobility(actor)
                if not components:
                    actors_without_mobility_components += 1
                    continue
                for component in components:
                    scanned_components += 1
                    ok, status = set_component_mobility(component, mobility_value)
                    if ok:
                        changed_components += 1
                    else:
                        failed_components += 1
                        unreal.log_warning(f"Mobility failed: actor={actor_label(actor)} component={component.get_name()} status={status}")

        if changed_components == 0:
            unreal.log_warning(
                f"Set mobility to {mobility_name} on 0 component(s). "
                f"Selected actors={len(selected_actors)}, scanned components={scanned_components}, "
                f"failed={failed_components}, actors_without_mobility_components={actors_without_mobility_components}."
            )
        else:
            unreal.log(
                f"Set mobility to {mobility_name} on {changed_components} component(s) "
                f"from {len(selected_actors)} selected actor(s). Scanned={scanned_components}, failed={failed_components}."
            )

