def needs_scale_reset(actor):
    try:
        scale = actor.get_actor_scale3d()
    except Exception:
        return False
    has_zero = scale.x == 0 or scale.y == 0 or scale.z == 0
    has_negative = scale.x < 0 or scale.y < 0 or scale.z < 0
    return (reset_zero_scale and has_zero) or (reset_negative_scale and has_negative)

if not selected_actors:
    unreal.log_warning("No actors are selected.")
else:
    changed_count = 0
    target = unreal.Vector(target_scale, target_scale, target_scale)
    with unreal.ScopedEditorTransaction("Reset Bad Scale On Selected Actors"):
        for actor in selected_actors:
            if not needs_scale_reset(actor):
                continue
            actor.modify()
            actor.set_actor_scale3d(target)
            changed_count += 1
    unreal.log(f"Reset scale on {changed_count} of {len(selected_actors)} selected actor(s).")
